mapper.select:
SELECT s.id, s.name, CONCAT_WS(', ',s.city, s.state) AS address, CASE WHEN s.ac_capacity > 0 THEN "A" ELSE "D" END AS priorityLabel FROM site s LEFT JOIN site_employee_map sem ON sem.id_site = s.id
JOIN device d ON d.id_site = s.id JOIN alert a ON a.id_device = d.id JOIN error e ON e.id = a.id_error
WHERE s.is_delete = 0 AND s.`status` = 1
AND sem.id_employee = #{userId}
AND a.`status` = 1 AND a.is_delete = 0 AND e.`status` = 1 AND e.`is_delete` = 0 AND d.`status` = 1 AND d.is_delete = 0 AND s.enable_alert = 1
GROUP BY s.id ORDER BY s.name ASC LIMIT #{limit} OFFSET #{offset}
